/**
 * Send a notification through the appropriate channel adapter.
 * Notifications for the same recipient are queued and delivered in order.
 * Emits notification:sent or notification:failed events after delivery.
 */
async send(payload: NotificationPayload): Promise<NotificationRecord> {
  const recipient = payload.recipient;
  const previous = this.recipientQueues.get(recipient) ?? Promise.resolve(undefined as unknown as NotificationRecord);
  const current = previous.catch(() => {/* don't let a prior failure block the queue */}).then(() => this.doSend(payload));
  this.recipientQueues.set(recipient, current);
  // Clean up the queue entry when this is the last item to avoid memory leaks
  current.finally(() => {
    if (this.recipientQueues.get(recipient) === current) {
      this.recipientQueues.delete(recipient);
    }
  });
  return current;
}

/**
 * Internal send implementation — performs the actual delivery.
 */
private async doSend(payload: NotificationPayload): Promise<NotificationRecord> {
  // Check user preferences before sending (if preferences service is configured).
  // Supports all channels: email, sms, webhook. Unknown channels (e.g. in-app) are allowed by default.
  if (this.preferencesService) {
    const userId = (payload.metadata?.['userId'] as string) ?? payload.recipient;
    if (!this.preferencesService.shouldSend(payload.channel, userId, payload.notificationType)) {
      this.logger.info(
        `Notification suppressed by user preferences: ${payload.notificationType} via ${payload.channel} for ${payload.recipient}`,
      );
      const record = this.createRecord(payload, false, true);
      // Suppressed notifications don't emit events, so log directly
      if (this.historyService) {
        this.historyService.log(record, payload.metadata);
      }
      return record;
    }
  }

  const adapter = this.adapters.get(payload.channel);

  if (!adapter) {
    const record = this.createRecord(payload, false);
    const errorMsg = `No adapter registered for channel: ${payload.channel}`;
    this.logger.error(errorMsg);
    await this.eventBus.emit({
      type: 'notification:failed',
      notification: record,
      error: errorMsg,
      timestamp: new Date(),
    });
    return record;
  }

  const result = await adapter.send(payload);
  const record = this.createRecord(payload, result.success);

  if (result.success) {
    this.logger.info(`Notification ${record.id} sent via ${payload.channel} to ${payload.recipient}`);
    await this.eventBus.emit({
      type: 'notification:sent',
      notification: record,
      timestamp: new Date(),
    });
  } else {
    this.logger.error(`Notification ${record.id} failed via ${payload.channel}: ${result.message}`);
    await this.eventBus.emit({
      type: 'notification:failed',
      notification: record,
      error: result.message ?? 'Unknown error',
      timestamp: new Date(),
    });
  }

  return record;
}

